fields.collector:
$wuKey = 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate'
$auKey = 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate\AU'
$ccmKey = 'HKLM:\SOFTWARE\Microsoft\CCM'
$read = {
    param($Key, $Name)
    try { "$((Get-ItemProperty -Path $Key -Name $Name -ErrorAction Stop).$Name)" } catch { '' }
}
$wuNames = @('AutoRestartDeadlinePeriodInDays', 'AutoRestartNotificationSchedule', 'AutoRestartRequiredNotificationDismissal', 'BranchReadinessLevel', 'DeferFeatureUpdates', 'DeferFeatureUpdatesPeriodInDays', 'DeferQualityUpdates', 'DeferQualityUpdatesPeriodInDays', 'DisableDualScan', 'DoNotConnectToWindowsUpdateInternetLocations', 'ElevateNonAdmins', 'EngagedRestartDeadline', 'EngagedRestartSnoozeSchedule', 'EngagedRestartTransitionSchedule', 'PauseFeatureUpdatesStartTime', 'PauseQualityUpdatesStartTime', 'ScheduleImminentRestartWarning', 'ScheduleRestartWarning', 'SetAutoRestartDeadline', 'SetAutoRestartNotificationConfig', 'SetAutoRestartNotificationDisable', 'SetAutoRestartRequiredNotificationDismissal', 'SetEDURestart', 'SetEngagedRestartTransitionSchedule', 'SetRestartWarningSchd', 'WUServer', 'WUStatusServer', 'SetPolicyDrivenUpdateSourceForDriverUpdates', 'SetPolicyDrivenUpdateSourceForFeatureUpdates', 'SetPolicyDrivenUpdateSourceForOtherUpdates', 'SetPolicyDrivenUpdateSourceForQualityUpdates')
$auNames = @('AutoInstallMinorUpdates', 'EnableFeaturedSoftware', 'IncludeRecommendedUpdates', 'NoAUAsDefaultShutdownOption', 'NoAUShutdownOption', 'NoAutoRebootWithLoggedOnUsers', 'NoAutoUpdate', 'RebootRelaunchTimeout', 'RebootRelaunchTimeoutEnabled', 'RebootWarningTimeout', 'RebootWarningTimeoutEnabled', 'RescheduleWaitTime', 'RescheduleWaitTimeEnabled')
$coMgmtWorkloadValues = @(17, 19, 21, 23, 25, 27, 29, 31, 49, 51, 53, 55, 57, 59, 61, 63, 81, 83, 85, 87, 89, 91, 93, 95, 113, 115, 117, 119, 121, 123, 125, 127, 145, 147, 149, 151, 153, 155, 157, 159, 177, 179, 181, 183, 185, 187, 189, 191, 209, 211, 213, 215, 217, 219, 221, 223, 241, 243, 245, 247, 249, 251, 253, 255)
$settings = [ordered]@{}
$coMgmtValue = & $read $ccmKey 'CoManagementFlags'
$settings['CoMgmtValue'] = $coMgmtValue
$settings['CoMgmtWorkload'] = "$([bool](($coMgmtValue -as [int]) -in $coMgmtWorkloadValues))"
foreach ($n in $wuNames) { $settings[$n] = & $read $wuKey $n }
foreach ($n in $auNames) { $settings[$n] = & $read $auKey $n }
[pscustomobject]$settings

$key = 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\DataCollection'
$item = Get-ItemProperty -Path $key -ErrorAction SilentlyContinue
$settings = [ordered]@{}
if ($item) {
    foreach ($p in $item.PSObject.Properties) {
        if ($p.Name -like 'PS*') { continue }
        $settings[$p.Name] = "$($p.Value)"
    }
}
[pscustomobject]$settings
